func TestFFTExt6(t *testing.T) {
	parameters := gopter.DefaultTestParameters()
	parameters.MinSuccessfulTests = 6
	properties := gopter.NewProperties(parameters)

	for maxSize := 2; maxSize <= 1<<10; maxSize <<= 1 {

		domainWithPrecompute := NewDomain(uint64(maxSize))
		domainWithoutPrecompute := NewDomain(uint64(maxSize), WithoutPrecompute())

		for domainName, domain := range map[string]*Domain{
			"with precompute":    domainWithPrecompute,
			"without precompute": domainWithoutPrecompute,
		} {
			t.Logf("domain: %s", domainName)
			properties.Property("DIF FFT should be consistent with dual basis", prop.ForAll(

				// checks that a random evaluation of a dual function eval(gen**ithpower) is consistent with the FFT result
				func(ithpower int) bool {

					pol := make([]fext.E6, maxSize)
					backupPol := make([]fext.E6, maxSize)

					for i := range maxSize {
						pol[i].MustSetRandom()
					}
					copy(backupPol, pol)

					domain.FFTExt6(pol, DIF)
					utils.BitReverse(pol)

					sample := domain.Generator
					sample.Exp(sample, big.NewInt(int64(ithpower)))

					eval := evaluatePolynomialExt6(backupPol, sample)

					return eval.Equal(&pol[ithpower])

				},
				gen.IntRange(0, maxSize-1),
			))

			properties.Property("DIF FFT on cosets should be consistent with dual basis", prop.ForAll(

				// checks that a random evaluation of a dual function eval(gen**ithpower) is consistent with the FFT result
				func(ithpower int) bool {

					pol := make([]fext.E6, maxSize)
					backupPol := make([]fext.E6, maxSize)

					for i := range maxSize {
						pol[i].MustSetRandom()
					}
					copy(backupPol, pol)

					domain.FFTExt6(pol, DIF, OnCoset())
					utils.BitReverse(pol)

					sample := domain.Generator
					sample.Exp(sample, big.NewInt(int64(ithpower))).
						Mul(&sample, &domain.FrMultiplicativeGen)

					eval := evaluatePolynomialExt6(backupPol, sample)

					return eval.Equal(&pol[ithpower])

				},
				gen.IntRange(0, maxSize-1),
			))

			properties.Property("DIT FFT should be consistent with dual basis", prop.ForAll(

				// checks that a random evaluation of a dual function eval(gen**ithpower) is consistent with the FFT result
				func(ithpower int) bool {

					pol := make([]fext.E6, maxSize)
					backupPol := make([]fext.E6, maxSize)

					for i := range maxSize {
						pol[i].MustSetRandom()
					}
					copy(backupPol, pol)

					utils.BitReverse(pol)
					domain.FFTExt6(pol, DIT)

					sample := domain.Generator
					sample.Exp(sample, big.NewInt(int64(ithpower)))

					eval := evaluatePolynomialExt6(backupPol, sample)

					return eval.Equal(&pol[ithpower])

				},
				gen.IntRange(0, maxSize-1),
			))

			properties.Property("bitReverse(DIF FFT(DIT FFT (bitReverse))))==id", prop.ForAll(

				func() bool {

					pol := make([]fext.E6, maxSize)
					backupPol := make([]fext.E6, maxSize)

					for i := range maxSize {
						pol[i].MustSetRandom()
					}
					copy(backupPol, pol)

					utils.BitReverse(pol)
					domain.FFTExt6(pol, DIT)
					domain.FFTInverseExt6(pol, DIF)
					utils.BitReverse(pol)

					check := true
					for i := range len(pol) {
						check = check && pol[i].Equal(&backupPol[i])
					}
					return check
				},
			))

			for nbCosets := 2; nbCosets < 5; nbCosets++ {
				properties.Property(fmt.Sprintf("bitReverse(DIF FFT(DIT FFT (bitReverse))))==id on %d cosets", nbCosets), prop.ForAll(

					func() bool {

						pol := make([]fext.E6, maxSize)
						backupPol := make([]fext.E6, maxSize)

						for i := range maxSize {
							pol[i].MustSetRandom()
						}
						copy(backupPol, pol)

						check := true

						for i := 1; i <= nbCosets; i++ {

							utils.BitReverse(pol)
							domain.FFTExt6(pol, DIT, OnCoset())
							domain.FFTInverseExt6(pol, DIF, OnCoset())
							utils.BitReverse(pol)

							for i := range len(pol) {
								check = check && pol[i].Equal(&backupPol[i])
							}
						}

						return check
					},
				))
			}

			properties.Property("DIT FFT(DIF FFT)==id", prop.ForAll(

				func() bool {

					pol := make([]fext.E6, maxSize)
					backupPol := make([]fext.E6, maxSize)

					for i := range maxSize {
						pol[i].MustSetRandom()
					}
					copy(backupPol, pol)

					domain.FFTInverseExt6(pol, DIF)
					domain.FFTExt6(pol, DIT)

					check := true
					for i := range len(pol) {
						check = check && pol[i].Equal(&backupPol[i])
					}
					return check
				},
			))

			properties.Property("DIT FFT(DIF FFT)==id on cosets", prop.ForAll(

				func() bool {

					pol := make([]fext.E6, maxSize)
					backupPol := make([]fext.E6, maxSize)

					for i := range maxSize {
						pol[i].MustSetRandom()
					}
					copy(backupPol, pol)

					domain.FFTInverseExt6(pol, DIF, OnCoset())
					domain.FFTExt6(pol, DIT, OnCoset())

					for i := range len(pol) {
						if !(pol[i].Equal(&backupPol[i])) {
							return false
						}
					}

					// compute with nbTasks == 1
					domain.FFTInverseExt6(pol, DIF, OnCoset(), WithNbTasks(1))
					domain.FFTExt6(pol, DIT, OnCoset(), WithNbTasks(1))

					for i := range len(pol) {
						if !(pol[i].Equal(&backupPol[i])) {
							return false
						}
					}

					return true
				},
			))
		}
		properties.TestingRun(t, gopter.ConsoleReporter(false))
	}

}

func randElementExt6(rng *rand.Rand) fext.E6 {
	var v fext.E6
	v.B0.A0 = babybear.Element{rng.Uint32N(2013265921)}
	v.B0.A1 = babybear.Element{rng.Uint32N(2013265921)}
	v.B1.A0 = babybear.Element{rng.Uint32N(2013265921)}
	v.B1.A1 = babybear.Element{rng.Uint32N(2013265921)}
	v.B2.A0 = babybear.Element{rng.Uint32N(2013265921)}
	v.B2.A1 = babybear.Element{rng.Uint32N(2013265921)}
	return v
}

func FuzzFFTExt6(f *testing.F) {
	f.Fuzz(func(t *testing.T, domainSize uint16, rngSeed int64) {
		if domainSize > (1 << 13) {
			t.Skip("domain size too large")
		}
		if domainSize < 2 {
			t.Skip("domain size too small")
		}

		domain := NewDomain(uint64(domainSize))

		var seed [32]byte
		binary.PutVarint(seed[:], rngSeed)
		// #nosec G404 -- fuzz does not require a cryptographic PRNG
		rng := rand.New(rand.NewChaCha8(seed))

		cardinality := domain.Cardinality

		// we just check that FFT-1(FFT(pol)) == pol
		a, b := make([]fext.E6, cardinality), make([]fext.E6, cardinality)
		for i := range int(cardinality) {
			a[i] = randElementExt6(rng)
		}
		copy(b, a)

		domain.FFTInverseExt6(a, DIF)
		domain.FFTExt6(a, DIT)

		assert := require.New(t)
		for i := range int(cardinality) {
			assert.True(a[i].Equal(&b[i]), "FFT-1(FFT(pol)) != pol at index %d", i)
		}
	})
}

