func evaluatePolynomialExt6(pol []fext.E6, val babybear.Element) fext.E6 {
	var res, tmp fext.E6
	var acc babybear.Element
	res.Set(&pol[0])
	acc.Set(&val)
	for i := 1; i < len(pol); i++ {
		tmp.MulByElement(&pol[i], &acc)
		res.Add(&res, &tmp)
		acc.Mul(&acc, &val)
	}
	return res
}
